     8→#include <sofa/pbrpc/compressed_stream.h>
     9→#include <sofa/pbrpc/rpc_error_code.h>
    10→#include <sofa/pbrpc/rpc_server_stream.h>
    11→
    12→namespace sofa {
    13→namespace pbrpc {
    14→
    15→BinaryRpcRequest::BinaryRpcRequest() : _req_body(new ReadBuffer())
    16→{
    17→}
    18→
    19→BinaryRpcRequest::~BinaryRpcRequest()
    20→{
    21→}
    22→
    23→RpcRequest::RpcRequestType BinaryRpcRequest::RequestType()
    24→{
    25→    return RpcRequest::BINARY;
    26→}
    27→
    28→std::string BinaryRpcRequest::Method()
    29→{
    30→    return _req_meta.method();
    31→}
    32→
    33→uint64 BinaryRpcRequest::SequenceId()
    34→{
    35→    return _req_meta.sequence_id();
    36→}
    37→
    38→void BinaryRpcRequest::ProcessRequest(
    39→        const RpcServerStreamWPtr& stream,
    40→        const ServicePoolPtr& service_pool)
    41→{
    42→    std::string service_name;
    43→    std::string method_name;
    44→    if (!ParseMethodFullName(_req_meta.method(), &service_name, &method_name))
    45→    {
    46→#if defined( LOG )
    47→        LOG(ERROR) << "ProcessRequest(): " << RpcEndpointToString(_remote_endpoint)
    48→                   << ": {" << _req_meta.sequence_id() << "}"
    49→                   << ": invalid method full name: " << _req_meta.method();
    50→#else
    51→        SLOG(ERROR, "ProcessRequest(): %s: {%lu}: invalid method full name: %s",
    52→                RpcEndpointToString(_remote_endpoint).c_str(),
    53→                _req_meta.sequence_id(), _req_meta.method().c_str());
    54→#endif
    55→        SendFailedResponse(stream,
    56→                RPC_ERROR_PARSE_METHOD_NAME, "method full name: " + _req_meta.method());
    57→        return;
    58→    }
    59→
    60→    MethodBoard* method_board = FindMethodBoard(service_pool, service_name, method_name);
    61→    if (method_board == NULL)
    62→    {
    63→#if defined( LOG )
    64→        LOG(ERROR) << "ProcessRequest(): " << RpcEndpointToString(_remote_endpoint)
    65→                   << ": {" << _req_meta.sequence_id() << "}"
    66→                   << ": method not found: " << _req_meta.method();
    67→#else
    68→        SLOG(ERROR, "ProcessRequest(): %s: {%lu}: method not found: %s",
    69→                RpcEndpointToString(_remote_endpoint).c_str(),
    70→                _req_meta.sequence_id(), _req_meta.method().c_str());
    71→#endif
    72→        SendFailedResponse(stream,
    73→                RPC_ERROR_FOUND_METHOD, "method full name: " + _req_meta.method());
    74→        return;
    75→    }
    76→
    77→    google::protobuf::Service* service = method_board->GetServiceBoard()->Service();
    78→    const google::protobuf::MethodDescriptor* method_desc = method_board->Descriptor();
    79→
    80→    google::protobuf::Message* request = service->GetRequestPrototype(method_desc).New();
    81→    CompressType compress_type =
    82→        _req_meta.has_compress_type() ? _req_meta.compress_type(): CompressTypeNone;
    83→    bool parse_request_return = false;
    84→    if (compress_type == CompressTypeNone)
    85→    {
    86→        parse_request_return = request->ParseFromZeroCopyStream(_req_body.get());
    87→    }
    88→    else
    89→    {
    90→        sofa::pbrpc::scoped_ptr<AbstractCompressedInputStream> is(
    91→                get_compressed_input_stream(_req_body.get(), compress_type));
    92→        parse_request_return = request->ParseFromZeroCopyStream(is.get());
    93→    }
    94→    if (!parse_request_return)
    95→    {
    96→#if defined( LOG )
    97→        LOG(ERROR) << "ProcessRequest(): " << RpcEndpointToString(_remote_endpoint)
    98→                   << ": {" << _req_meta.sequence_id() << "}: parse request message failed";
    99→#else
   100→        SLOG(ERROR, "ProcessRequest(): %s: {%lu}: parse request message failed",
   101→                RpcEndpointToString(_remote_endpoint).c_str(), _req_meta.sequence_id());
   102→#endif
   103→        SendFailedResponse(stream,
   104→                RPC_ERROR_PARSE_REQUEST_MESSAGE, "method full name: " + _req_meta.method());
   105→        delete request;
   106→        return;
   107→    }
   108→
   109→    google::protobuf::Message* response = service->GetResponsePrototype(method_desc).New();
   110→
   111→    RpcController* controller = new RpcController();
   112→    const RpcControllerImplPtr& cntl = controller->impl();
   113→    cntl->SetSequenceId(_req_meta.sequence_id());
   114→    cntl->SetMethodId(_req_meta.method());
   115→    cntl->SetLocalEndpoint(_local_endpoint);
   116→    cntl->SetRemoteEndpoint(_remote_endpoint);
   117→    cntl->SetRpcServerStream(stream);
   118→    cntl->SetRequestReceivedTime(_received_time);
   119→    cntl->SetStartProcessTime(ptime_now());
   120→    cntl->SetResponseCompressType(_req_meta.has_expected_response_compress_type() ?
   121→            _req_meta.expected_response_compress_type() : CompressTypeNone);
   122→
   123→    CallMethod(method_board, controller, request, response);
   124→}
   125→
   126→ReadBufferPtr BinaryRpcRequest::AssembleSucceedResponse(
   127→        const RpcControllerImplPtr& cntl,
   128→        const google::protobuf::Message* response,
   129→        std::string& err)
   130→{
   131→    RpcMeta meta;
   132→    meta.set_type(RpcMeta::RESPONSE);
   133→    meta.set_sequence_id(cntl->SequenceId());
   134→    meta.set_failed(false);
   135→    meta.set_compress_type(cntl->ResponseCompressType());
   136→
   137→    RpcMessageHeader header;
   138→    int header_size = static_cast<int>(sizeof(header));
   139→    WriteBuffer write_buffer;
   140→    int64 header_pos = write_buffer.Reserve(header_size);
   141→    if (header_pos < 0)
   142→    {
   143→        err = "reserve rpc message header failed";
   144→        return ReadBufferPtr();
   145→    }
   146→    if (!meta.SerializeToZeroCopyStream(&write_buffer))
   147→    {
   148→        err = "serialize rpc meta failed";
   149→        return ReadBufferPtr();
   150→    }
   151→    header.meta_size = static_cast<int>(write_buffer.ByteCount() - header_pos - header_size);
   152→    bool ser_ret = false;
   153→    if (meta.compress_type() == CompressTypeNone)
   154→    {
   155→        ser_ret = response->SerializeToZeroCopyStream(&write_buffer);
   156→    }
   157→    else
   158→    {
   159→        sofa::pbrpc::scoped_ptr<AbstractCompressedOutputStream> os(
   160→                get_compressed_output_stream(&write_buffer, meta.compress_type()));
   161→        ser_ret = response->SerializeToZeroCopyStream(os.get());
   162→        os->Flush();
   163→    }
   164→    if (!ser_ret)
   165→    {
   166→        err = "serialize response message failed";
   167→        return ReadBufferPtr();
   168→    }
   169→    header.data_size = write_buffer.ByteCount() - header_pos - header_size - header.meta_size;
   170→    header.message_size = header.meta_size + header.data_size;
   171→    write_buffer.SetData(header_pos, reinterpret_cast<const char*>(&header), header_size);
   172→
   173→    ReadBufferPtr read_buffer(new ReadBuffer());
   174→    write_buffer.SwapOut(read_buffer.get());
   175→
   176→    return read_buffer;
   177→}
   178→
   179→ReadBufferPtr BinaryRpcRequest::AssembleFailedResponse(
   180→        int32 error_code,
   181→        const std::string& reason,
   182→        std::string& err)
   183→{
   184→    RpcMeta meta;
   185→    meta.set_type(RpcMeta::RESPONSE);
   186→    meta.set_sequence_id(_req_meta.sequence_id());
   187→    meta.set_failed(true);
   188→    meta.set_error_code(error_code);
   189→    meta.set_reason(reason);
   190→
   191→    RpcMessageHeader header;
   192→    int header_size = static_cast<int>(sizeof(header));
   193→    WriteBuffer write_buffer;
   194→    int64 header_pos = write_buffer.Reserve(header_size);
   195→    if (header_pos < 0)
   196→    {
   197→        err = "reserve rpc message header failed";
   198→        return ReadBufferPtr();
   199→    }
   200→    if (!meta.SerializeToZeroCopyStream(&write_buffer))
   201→    {
   202→        err = "serialize rpc meta failed";
   203→        return ReadBufferPtr();
   204→    }
   205→    header.meta_size = static_cast<int>(write_buffer.ByteCount() - header_pos - header_size);
   206→    header.data_size = 0;
   207→    header.message_size = header.meta_size + header.data_size;
   208→    write_buffer.SetData(header_pos, reinterpret_cast<const char*>(&header), header_size);
   209→
   210→    ReadBufferPtr read_buffer(new ReadBuffer());
   211→    write_buffer.SwapOut(read_buffer.get());
   212→
   213→    return read_buffer;
   214→}
   215→
   216→} // namespace pbrpc
   217→} // namespace sofa
